SELECT tcs.id, tcs.COMPANY_ID, tcs.COMPANY_NAME, tcs.STATEMENT_NO, tcs.IS_ENTER, tcs.CUSTOMER_ID, tcs.CUSTOMER_NAME, tcs."TYPE" typeCode, mdd.DICT_LABEL TYPE, tcs.TRUST_ID, tcs.TRUST_CARGO_ID, tcs.HANDOVERLIST_ID, tcs.SHIPVOYAGE_ID, tcs.SHIPVOYAGE_ITEM_ID, tcs.CARGO_CODE, tcs.CARGO_NAME, COALESCE( to_char( tcs.TRADE_TYPE ), to_char( tds.TRADE_TYPE ) ) TRADE_TYPE, tcs.SETTLEMENT_DATE, mdd1.DICT_LABEL statusLabel, tcs.status, tcs.CREATE_BY_NAME, tcs.CREATE_TIME, tcs.IS_FINAL, tcs.CREATE_BY_NAME STATEMENT_BY_NAME, tcs.CREATE_TIME STATEMENT_TIME, tcs.REVIEW_BY_NAME, tcs.REVIEW_TIME, tcs.CONFIRM_BY_NAME, tcs.CONFIRM_TIME, tcs.SETTLEMENT_BASIS_CODE, tcs.SETTLEMENT_BASIS_NAME, tcs.TAX_INVOICE_CODE, tcs.TAX_INVOICE_NAME, tcs.RECEIPT_REMARK, tcs.REJECT_BY_NAME, tcs.REJECT_TIME, tcs.REJECT_REASON, tcs.BONDED_AREA_TON, nvl( tcs.SHIP_NAME_VOYAGE, tds.SHIP_NAME || '_' || tdsi.VOYAGE ) shipNameVoyage, sum( tcsd.AMOUNT ) amount, sum( NVL( tcsd.AMOUNTJF, tcsd.AMOUNT ) ) amountjf, sum( NVL( tcsd.AMOUNTZK, 0 ) ) amountzk, sum( NVL( tcsd.INVOICE_AMOUNT, 0 ) ) invoiceAmount, tcs.FINANCE_STATUS, decode( tcs.FINANCE_STATUS, '10', '未审核', '已审核' ) financeStatusLabel, tcs.FINANCE_BY_NAME, tcs.FINANCE_TIME, tcs.CARGO_INFO_ID, tcs.CONTRACT_NO, sum( nvl( tcsd.UTILIZED_AMOUNT, 0 ) ) UTILIZED_AMOUNT_SUM, tcs.IS_PRINT, tci.CARGO_INFO_NO CARGO_INFO_NO, LISTAGG ( TO_CHAR( tcsd.RATE_ITEM_CODE ), ',' ) WITHIN GROUP ( ORDER BY tcsd.RATE_ITEM_CODE ) RATE_ITEM_CODE, LISTAGG ( TO_CHAR( tcsd.RATE_ITEM_NAME ), ',' ) WITHIN GROUP ( ORDER BY tcsd.RATE_ITEM_NAME ) RATE_ITEM_NAME FROM T_COST_STATEMENT tcs LEFT JOIN T_COST_STATEMENT_DETAIL tcsd ON tcs.id = tcsd."STATEMENT" LEFT JOIN T_DIS_SHIPVOYAGE_ITEM tdsi ON tcs.SHIPVOYAGE_ITEM_ID = tdsi.ID LEFT JOIN T_DIS_SHIPVOYAGE tds ON tdsi.SHIPVOYAGE_ID = tds.ID LEFT JOIN M_DICT_DATA mdd ON ( mdd.DICT_VALUE = tcs.TYPE AND mdd.DICT_TYPE = 'HANDOVERLIST_TYPE' ) LEFT JOIN M_DICT_DATA mdd1 ON ( mdd1.DICT_VALUE = tcs.status AND mdd1.DICT_TYPE = 'STATEMENT_STATUS' ) LEFT JOIN T_BUS_TRUST_CARGO ttc ON ttc.ID = tcs.TRUST_CARGO_ID LEFT JOIN T_BUS_CARGO_INFO tci ON tci.ID = ttc.CARGO_INFO_ID where 1=1
and nvl( tcs.SHIP_NAME_VOYAGE, tds.SHIP_NAME || '_' || tdsi.VOYAGE ) like #{shipNameLike}
and tdsi.VOYAGE like #{voyageLike}
and tci.CARGO_INFO_NO like #{cargoInfoNoLike}
