SELECT
sum(tcsd.AMOUNT) amount,
sum(NVL(tcsd.INVOICE_AMOUNT,0)) invoiceAmount,
sum(nvl(tcsd.UTILIZED_AMOUNT,0)) UTILIZED_AMOUNT_SUM
FROM
T_COST_STATEMENT tcs
LEFT JOIN T_COST_STATEMENT_DETAIL tcsd ON tcs.id = tcsd."STATEMENT"
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM tdsi ON tcs.SHIPVOYAGE_ITEM_ID = tdsi.ID
LEFT JOIN T_DIS_SHIPVOYAGE tds ON tdsi.SHIPVOYAGE_ID = tds.ID
LEFT JOIN M_DICT_DATA mdd ON ( mdd.DICT_VALUE = tcs.TYPE AND mdd.DICT_TYPE = 'HANDOVERLIST_TYPE' )
LEFT JOIN M_DICT_DATA mdd1 ON ( mdd1.DICT_VALUE = tcs.status AND mdd1.DICT_TYPE = 'STATEMENT_STATUS' )
LEFT JOIN T_BUS_TRUST_CARGO ttc ON ttc.ID = tcs.TRUST_CARGO_ID
LEFT JOIN T_BUS_CARGO_INFO tci ON tci.ID = ttc.CARGO_INFO_ID
where
1=1


    and nvl( tcs.SHIP_NAME_VOYAGE, tds.SHIP_NAME || '_' || tdsi.VOYAGE ) like #{shipNameLike}



    and tdsi.VOYAGE like #{voyageLike}



    and tci.CARGO_INFO_NO like #{cargoInfoNoLike}


    and tcs.CUSTOMER_ID = #{customerId}


    and to_char(tcs.SETTLEMENT_DATE,'yyyy-MM') = #{month}


    and to_char(tcs.SETTLEMENT_DATE,'yyyy-MM') >= #{months}


    and to_char(tcs.SETTLEMENT_DATE,'yyyy-MM') <= #{monthe}


    and tcs.TYPE = #{type}


    and tcs.STATUS = #{status}


    and tcs.FINANCE_STATUS = #{financeStatus}


    and tcs.COMPANY_ID = #{companyId}


    and tcs.IS_PRINT = '1'


    and tcs.IS_PRINT is null



    and tcs.STATEMENT_NO like #{statementNoLike}

SELECT
sum(NVL(tcsd.INVOICE_AMOUNT,0)) invoiceAmount,
sum(tcsd.AMOUNT)-sum(NVL(tcsd.INVOICE_AMOUNT,0)) invoiceAmountsy,
sum(nvl(tcsd.UTILIZED_AMOUNT,0)) UTILIZED_AMOUNT,
sum(tcsd.AMOUNT)-sum(nvl(tcsd.UTILIZED_AMOUNT,0)) UTILIZED_AMOUNTSY,
sum(tcsd.AMOUNT) AMOUNT
FROM
T_COST_STATEMENT tcs
LEFT JOIN T_COST_STATEMENT_DETAIL tcsd ON tcs.id = tcsd."STATEMENT"
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM tdsi ON tcs.SHIPVOYAGE_ITEM_ID  = tdsi.ID
LEFT JOIN T_DIS_SHIPVOYAGE tds ON tdsi.SHIPVOYAGE_ID = tds.ID
left join M_DICT_DATA mdd on (mdd.DICT_VALUE = tcs.type and mdd.DICT_TYPE = 'HANDOVERLIST_TYPE')
left join M_DICT_DATA mdd1 on (mdd1.DICT_VALUE = tcs.status and mdd1.DICT_TYPE = 'STATEMENT_STATUS')
left join T_BUS_TRUST_CARGO ttc on ttc.ID = tcs.TRUST_CARGO_ID
left join T_BUS_CARGO_INFO tci on tci.ID = ttc.CARGO_INFO_ID
left join T_BUS_CARGO_INFO tci1 on tci1.ID = tcs.CARGO_INFO_ID
left join T_COST_TUG_FEE tctf on tctf.ID = tcs.TUG_FEE_ID
left join T_DIS_TUG_SERVICE tdts on tdts.ID = tctf.TUG_SERVICE_ID
where
1=1


    and nvl(tcs.SHIP_NAME_VOYAGE,nvl(tdts.SHIP_NAME,tds.SHIP_NAME)) like #{shipNameLike}



    and tdsi.VOYAGE like #{voyageLike}



    and (tci.CARGO_INFO_NO like #{cargoInfoNoLike} or tci1.CARGO_INFO_NO like #{cargoInfoNoLike})


    and tcs.CUSTOMER_ID = #{customerId}


    and to_char(tcs.SETTLEMENT_DATE,'yyyy-MM-dd') >= #{months}
    and to_char(tcs.SETTLEMENT_DATE,'yyyy-MM-dd') <= #{monthe}


    and tcs.TYPE = #{type}


    and tcs.PAY_TYPE_CODE = #{payTypeCode}


    and tcs.STATUS = #{status}


    and tcs.FINANCE_STATUS = #{financeStatus}


    and tcs.COMPANY_ID = #{companyId}


    and instr(#{rateItemCode},tcsd.RATE_ITEM_CODE)>0



    and tcs.STATEMENT_NO like #{statementNoLike}


    and NVL(tcsd.AMOUNTZK,0)>0


    and NVL(tcsd.AMOUNTZK,0)=0

mapper.update:
update T_COST_STATEMENT
set
    STATUS = #{status}
where
    ID = #{id}

update T_COST_SHIP set STATUS = 10, UPDATE_BY = #{loginUserId}, UPDATE_BY_NAME = #{loginUserName}, UPDATE_TIME = #{now} where SHIPVOYAGE_ID = #{shipvoyageId}
and type = '10'
and type = '20'
